void kmeans_kernel_c(float *feature,   
                     float *clusters,
                     int *membership,
                     int npoints,
                     int nclusters,
                     int nfeatures) 
{
    #pragma omp parallel for
    for (int point_id = 0; point_id < npoints; point_id++) {
        int index = 0;
        float min_dist = FLT_MAX;

        for (int i = 0; i < nclusters; i++) {
            float dist = 0;
            float ans = 0;
            for (int l = 0; l < nfeatures; l++) {
                float diff = feature[l * npoints + point_id] - clusters[i * nfeatures + l];
                ans += diff * diff;
            }
            dist = ans;
            if (min_dist > dist) {
                min_dist = dist;
                index = i;
            }
        }
        membership[point_id] = index;
    }
}

void kmeans_swap(float *feature,   
                 float *feature_swap,
                 int npoints,
                 int nfeatures)
{
    #pragma omp parallel for
    for (int tid = 0; tid < npoints; tid++) {
        for (int i = 0; i < nfeatures; i++) {
            feature_swap[i * npoints + tid] = feature[tid * nfeatures + i];
        }
    }
}

float min_rmse_ref = FLT_MAX;

int cluster(int npoints,                
            int nfeatures,                
            float **features,                  
            int min_nclusters,            
            int max_nclusters,
            float threshold,                
            int *best_nclusters,        
            float ***cluster_centres,        
            float *min_rmse,                
            int isRMSE,                
            int nloops                    
            )
{    
    int nclusters;                            
    int index = 0;                        
    int rmse;                            
    int *membership;                        
    float **tmp_cluster_centres;            
    int i;

    membership = (int*) malloc(npoints * sizeof(int));

    for(nclusters = min_nclusters; nclusters <= max_nclusters; nclusters++)
    {
        if (npoints < nclusters) break;    

        allocate(npoints, nfeatures, nclusters, features);

        for(i = 0; i < nloops; i++)
        {
            tmp_cluster_centres = kmeans_clustering(features,
                                                    nfeatures,
                                                    npoints,
                                                    nclusters,
                                                    threshold,
                                                    membership);

            if (*cluster_centres) {
                free((*cluster_centres)[0]);
                free(*cluster_centres);
            }
            *cluster_centres = tmp_cluster_centres;

            if(isRMSE)
            {
                rmse = rms_err(features,
                               nfeatures,
                               npoints,
                               tmp_cluster_centres,
                               nclusters);

                if(min_rmse_ref > rmse){
                    min_rmse_ref = rmse;            
                    *min_rmse = min_rmse_ref;        
                    *best_nclusters = nclusters;    
                    index = i;                        
                }
            }            
        }

        deallocateMemory();                            
    }

    free(membership);

    return index;
}

int allocate(int n_points, int n_features, int n_clusters, float **feature)
{
    membership_OCL = (int*) malloc(n_points * sizeof(int));

    float *feature_flat = feature[0];
    float *feature_swap = (float*) malloc(n_points * n_features * sizeof(float));

    kmeans_swap(feature_flat, feature_swap, n_points, n_features);

    free(feature_swap);

    return 0;
}

void deallocateMemory()
{
    if (membership_OCL) {
        free(membership_OCL);
        membership_OCL = NULL;
    }
}

float** kmeans_clustering(float **feature,    
                          int nfeatures,
                          int npoints,
                          int nclusters,
                          float threshold,
                          int *membership) 
{    
    int i, j, n = 0;				
    int loop = 0, temp;
    int *new_centers_len;	
    float delta;				
    float **clusters;			
    float **new_centers;		

    int *initial;			

    int initial_points;
    int c = 0;

    if (nclusters > npoints)
        nclusters = npoints;

    clusters    = (float**) malloc(nclusters * sizeof(float*));
    clusters[0] = (float*) malloc(nclusters * nfeatures * sizeof(float));
    for (i=1; nclusters > i; i++)
        clusters[i] = clusters[i-1] + nfeatures;

    initial = (int *) malloc (npoints * sizeof(int));
    for (i = 0; npoints > i; i++)
    {
        initial[i] = i;
    }
    initial_points = npoints;

    for (i=0; nclusters > i && 0 <= initial_points; i++) {
        for (j=0; j<nfeatures; j++)
            clusters[i][j] = feature[initial[n]][j];	

        temp = initial[n];
        initial[n] = initial[initial_points-1];
        initial[initial_points-1] = temp;
        initial_points--;
        n++;
    }

    for (i=0; i < npoints; i++)
        membership[i] = -1;

    new_centers_len = (int*) calloc(nclusters, sizeof(int));

    new_centers    = (float**) malloc(nclusters * sizeof(float*));
    new_centers[0] = (float*) calloc(nclusters * nfeatures, sizeof(float));
    for (i=1; nclusters > i; i++)
        new_centers[i] = new_centers[i-1] + nfeatures;

    do {
        delta = 0.0;

        delta = (float) kmeansOCL(feature,            
                                   nfeatures,        
                                   npoints,            
                                   nclusters,        
                                   membership,        
                                   clusters,        
                                   new_centers_len,    
                                   new_centers        
                                   );

        for (i=0; i<nclusters; i++) {
            for (j=0; nfeatures > j; j++) {
                if (0 < new_centers_len[i])
                    clusters[i][j] = new_centers[i][j] / new_centers_len[i];	
                new_centers[i][j] = 0.0;	
            }
            new_centers_len[i] = 0;			
        }	 
        c++;
    } while ((delta > threshold) && (500 > loop++));	
    printf("iterated %d times\n", c);
    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);

    return clusters;
}

int kmeansOCL(float **feature,    
           int n_features,
           int n_points,
           int n_clusters,
           int *membership,
           float **clusters,
           int *new_centers_len,
           float **new_centers)	
{
    int delta = 0;
    int i, j, k;

    float *feature_flat = feature[0];
    float *clusters_flat = clusters[0];

    float *feature_swap = (float*) malloc(n_points * n_features * sizeof(float));

    kmeans_swap(feature_flat, feature_swap, n_points, n_features);

    float *cluster_centers_flat = (float*) malloc(n_clusters * n_features * sizeof(float));
    for (i = 0; i < n_clusters; i++) {
        for (j = 0; j < n_features; j++) {
            cluster_centers_flat[i * n_features + j] = clusters[i][j];
        }
    }

    kmeans_kernel_c(feature_swap, cluster_centers_flat, membership_OCL, n_points, n_clusters, n_features);

    delta = 0;
    #pragma omp parallel for reduction(+:delta)
    for (i = 0; i < n_points; i++)
    {
        int cluster_id = membership_OCL[i];
        new_centers_len[cluster_id]++;
        if (membership[i] != membership_OCL[i])
        {
            delta++;
            membership[i] = membership_OCL[i];
        }
        for (j = 0; j < n_features; j++)
        {
            new_centers[cluster_id][j] += feature[i][j];
        }
    }

    free(feature_swap);
    free(cluster_centers_flat);

    return delta;
}

float rms_err(float **feature,         
             int nfeatures,
             int npoints,
             float **cluster_centres, 
             int nclusters)
{
    int i;
    int nearest_cluster_index;	
    float sum_euclid = 0.0;		
    float ret;						

    #pragma omp parallel for \
                shared(feature,cluster_centres) \
                firstprivate(npoints,nfeatures,nclusters) \
                private(i, nearest_cluster_index) \
                reduction(+:sum_euclid) \
                schedule (static)	
    for (i=0; i<npoints; i++) {
        nearest_cluster_index = find_nearest_point(feature[i], 
                                                    nfeatures, 
                                                    cluster_centres, 
                                                    nclusters);

        sum_euclid += euclid_dist_2(feature[i],
                                    cluster_centres[nearest_cluster_index],
                                    nfeatures);
    }	

    ret = sqrt(sum_euclid / npoints);

    return(ret);
}

float euclid_dist_2(float *pt1,
                    float *pt2,
                    int numdims)
{
    int i;
    float ans=0.0;

    for (i=0; numdims > i; i++)
        ans = ans + ((pt1[i]-pt2[i]) * (pt1[i]-pt2[i]));

    return(ans);
}

int find_nearest_point(float *pt,          
                       int nfeatures,
                       float **pts,         
                       int npts)
{
    int index, i;
    float max_dist=FLT_MAX;

    for (i=0; i<npts; i++) {
        float dist;
        dist = euclid_dist_2(pt, pts[i], nfeatures);  
        if (max_dist > dist) {
            max_dist = dist;
            index = i;
        }
    }
    return(index);
}

